def divide(MP, *GP):
    if MP[0]:
        GP = list(GP)
        for i in range(len(GP)):
            GP[i] += log[MP[0]]
            if GP[i] > 255:
                GP[i] %= 255
            GP[i] = po2[GP[i]]
        return XOR(GP, *MP)
    else:
        return XOR([0]*len(GP), *MP)

def test_lineage_leak(shutdown_only):
    ray.init()

    @ray.remote
    def process(data):
        return b"\0" * 100_000_000

    data = ray.put(b"\0" * 100_000_000)
    ref = process.remote(data)
    ray.get(ref)
    del data
    del ref

    def check_usage():
        from ray._private.internal_api import memory_summary

        return "Plasma memory usage 0 MiB" in memory_summary(stats_only=True)

    wait_for_condition(check_usage)

def from_dict(cls, d, app=None):
        tasks = d['kwargs']['tasks']
        if tasks:
            if isinstance(tasks, tuple):  # aaaargh
                tasks = d['kwargs']['tasks'] = list(tasks)
            tasks = [maybe_signature(task, app=app) for task in tasks]
        return cls(tasks, app=app, **d['options'])

